/* Chart.js Minimal Stub */
(function() {
  window.Chart = function(ctx, config) {
    this.ctx = ctx;
    this.config = config;
    this.data = config.data || {};
    const canvas = typeof ctx === 'string' ? document.getElementById(ctx) : ctx;
    if (!canvas) return;
    const c = canvas.getContext ? canvas.getContext('2d') : null;
    if (!c) return;
    c.fillStyle = '#f0f0f0';
    c.fillRect(0, 0, canvas.width, canvas.height);
    c.fillStyle = '#999';
    c.font = '14px Arial';
    c.textAlign = 'center';
    c.fillText('[Chart Placeholder]', canvas.width / 2, canvas.height / 2);
  };
  window.Chart.defaults = {};
})();
